def largest_subset(numbers):
    """
    Find the size of the largest subset of a list of numbers so that every pair is divisible.
    A pair is divisible if one divides the other.
    """
    if not numbers:
        return 0

    # Sort the numbers
    sorted_nums = sorted(numbers)
    n = len(sorted_nums)

    # dp[i] represents the length of the longest chain ending at index i
    dp = [1] * n

    for i in range(n):
        for j in range(i):
            # Check if sorted_nums[i] is divisible by sorted_nums[j]
            if sorted_nums[i] % sorted_nums[j] == 0:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)
